class VotingMachine:
    def __init__(self):
        self.votes = {}

    def add_candidate(self, name):
        if name not in self.votes:
            self.votes[name] = 0
            print(f"Added candidate: {name}")
        else:
            print(f"Candidate {name} already exists.")

    def remove_candidate(self, name):
        if name in self.votes:
            del self.votes[name]
            print(f"Removed candidate: {name}")
        else:
            print(f"Candidate {name} does not exist.")

    def update_votes(self, name, votes):
        if name in self.votes:
            self.votes[name] += votes
            print(f"Updated votes for {name} to {self.votes[name]}")
        else:
            print(f"Candidate {name} does not exist.")

    def cast_vote(self, name):
        if name in self.votes:
